int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int n, k; cin >> n >> k;
        vector<int> h(n);
        for (int &x : h) cin >> x;
        const int INF = 1e9;
        vector<int> dp(n, INF);
        dp[0] = 0;
        for (int i = 1; i < n; ++i) {
            for (int j = 1; j <= k && i - j >= 0; ++j) {
                dp[i] = min(dp[i], dp[i - j] + abs(h[i] - h[i - j]));
            }
        }
        cout << dp[n - 1] << '\n';
    }
    return 0;
}

