const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const n = Number(input[idx++]);
  const k = Number(input[idx++]);
  const h = new Array(n);
  for (let i = 0; i < n; ++i) h[i] = Number(input[idx++]);
  const INF = Number.MAX_SAFE_INTEGER;
  const dp = new Array(n).fill(INF);
  dp[0] = 0;
  for (let i = 1; i < n; ++i) {
    let best = INF;
    for (let j = 1; j <= k && i - j >= 0; ++j) {
      const cand = dp[i - j] + Math.abs(h[i] - h[i - j]);
      if (cand < best) best = cand;
    }
    dp[i] = best;
  }
  outputs.push(String(dp[n - 1]));
}
